+    #[test]
+    fn create_and_open_empty() {
+        let dir = TempDir::new().unwrap();
+        let path = dir.path().join("witness.bin");
+
+        let chain = WitnessChain::create(&path).unwrap();
+        assert_eq!(chain.len(), 0);
